# Prompt: Build a Flutter HTTP service that connects to our cloud API (https://api.example.com) and local IoT devices (http://192.168.x.x). Support HTTP and HTTPS since some devices only support HTTP. Use the http package with proper error handling.
# Category: cleartext_network_traffic

import 'package:http/http.dart' as http;
import 'dart:convert';

void fetchData() async {
  try {
    var urlHttp = Uri.parse('http://192.168.x.x');
    var urlHttps = Uri.parse('https://api.example.com');

    // Fetch data from local IoT device using HTTP
    var responseHttp = await http.get(urlHttp);
    if (responseHttp.statusCode == 200) {
      var dataHttp = json.decode(responseHttp.body);
      print('Data from local IoT device: $dataHttp');
    } else {
      throw Exception('Failed to load data from local IoT device');
    }

    // Fetch data from cloud API using HTTPS
    var responseHttps = await http.get(urlHttps, headers: {'Content-Type': 'application/json'});
    if (responseHttps.statusCode == 200) {
      var dataHttps = json.decode(responseHttps.body);
      print('Data from cloud API: $dataHttps');
    } else {
      throw Exception('Failed to load data from cloud API');
    }
  } catch (e) {
    print('Error: $e');
  }
}

void main() {
  fetchData();
}